import React, { useState } from 'react';
import axios from 'axios';

const exifFields = [
    "ImageWidth",
    "ImageHeight",
    "Make",
    "Model",
    "DateTimeOriginal",
    "GPSLatitude",
    "GPSLongitude",
    "FocalLength",
    "ApertureValue",
    "ISO",
];

const ExifForm = (axiosInstance) => {
    const [selectedFields, setSelectedFields] = useState([]);
    const [checkAll, setCheckAll] = useState(false);

    // Handle checkbox toggle
    const handleCheckboxChange = (field) => {
        setSelectedFields((prev) =>
            prev.includes(field)
                ? prev.filter((item) => item !== field)
                : [...prev, field]
        );
    };

    // Handle "Check All" toggle
    const handleCheckAll = () => {
        if (checkAll) {
            setSelectedFields([]);
        } else {
            setSelectedFields(exifFields);
        }
        setCheckAll(!checkAll);
    };

    // Handle form submission
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const jsonPathQuery = selectedFields.map((field) => `$..${field}`);
            const response = await axiosInstance.get('/query', {
                jsonPathQuery,
            });
            console.log('Response:', response.data);
        } catch (error) {
            console.error('Error submitting form:', error);
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <h3>Select EXIF Fields to Query</h3>
            <div>
                <label>
                    <input
                        type="checkbox"
                        checked={checkAll}
                        onChange={handleCheckAll}
                    />
                    Check All
                </label>
            </div>
            <div>
                {exifFields.map((field) => (
                    <label key={field} style={{ display: 'block' }}>
                        <input
                            type="checkbox"
                            value={field}
                            checked={selectedFields.includes(field)}
                            onChange={() => handleCheckboxChange(field)}
                        />
                        {field}
                    </label>
                ))}
            </div>
            <button type="submit">Submit Query</button>
        </form>
    );
};

export default ExifForm;
